#include<bits/stdc++.h>
using namespace std;
long long dp[550][550][6],n,k;
char s[550];
const long long mod=1e9+7;
int main()
{
    scanf("%lld%lld%s",&n,&k,s+1);
    for(long long i=1;i<=n;i++)
    {
        dp[i][i-1][0]=1;
    }
    for(long long len=1;len<=n;len++)
    {
        for(long long l=1,r=len;r<=n;l++,r++)
        {
            if(len<=k)
            {
                dp[l][r][0]=dp[l][r-1][0]&&(s[r]=='*'||s[r]=='?');
            }
            if(len>=2)
            {
                if((s[l]=='('||s[l]=='?')&&(s[r]==')'||s[r]=='?'))
                {
                    dp[l][r][1]=(dp[l+1][r-1][0]+dp[l+1][r-1][2]+dp[l+1][r-1][3]+dp[l+1][r-1][4])%mod;
                }
                for(long long i=l;i<r;i++)
                {
                    dp[l][r][2]=(dp[l][r][2]+dp[l][i][3]*dp[i+1][r][0]%mod)%mod;
                    dp[l][r][3]=(dp[l][r][3]+(dp[l][i][2]+dp[l][i][3])%mod*dp[i+1][r][1]%mod)%mod;
                    dp[l][r][4]=(dp[l][r][4]+(dp[l][i][4]+dp[l][i][5])%mod*dp[i+1][r][1]%mod)%mod;
                    dp[l][r][5]=(dp[l][r][5]+dp[l][i][4]*dp[i+1][r][0]);
                }
            }
            dp[l][r][3]=(dp[l][r][3]+dp[l][r][1])%mod;
            dp[l][r][5]=(dp[l][r][5]+dp[l][r][0])%mod;
        }
    }
    printf("%lld",dp[1][n][3]);
    return 0;
}
